TIER_HIERARCHY = {
    UserTier.BASIC: 0,
    UserTier.SILVER: 1,
    UserTier.GOLD: 2,
    UserTier.PLATINUM: 3,
    UserTier.ADMIN: 4,
}


def user_meets_tier_requirement(user: User, required_tier: UserTier) -> bool:
    """Server-side check: does the user's tier meet or exceed the required tier?"""
    return TIER_HIERARCHY.get(user.tier, 0) >= TIER_HIERARCHY.get(required_tier, 0)


