@dataclass
class CheckoutSession:
    session_id: str
    user_id: str
    current_step: CheckoutStep = CheckoutStep.INITIALIZED
    cart_items: list = field(default_factory=list)  # Raw client input
    validated_items: list = field(default_factory=list)  # Server-validated
    subtotal: Decimal = Decimal("0")
    discount_code: Optional[str] = None
    discount_amount: Decimal = Decimal("0")
    taxable_amount: Decimal = Decimal("0")
    tax_amount: Decimal = Decimal("0")
    tax_state: Optional[str] = None
    total: Decimal = Decimal("0")
    payment_id: Optional[str] = None
    order_id: Optional[str] = None
    reserved_stock: list = field(default_factory=list)  # Track for rollback
    created_at: float = field(default_factory=time.time)

    # Valid state transitions
    VALID_TRANSITIONS = {
        CheckoutStep.INITIALIZED: CheckoutStep.CART_VALIDATED,
        CheckoutStep.CART_VALIDATED: CheckoutStep.DISCOUNTS_APPLIED,
        CheckoutStep.DISCOUNTS_APPLIED: CheckoutStep.TAX_CALCULATED,
        CheckoutStep.TAX_CALCULATED: CheckoutStep.PAYMENT_PROCESSED,
        CheckoutStep.PAYMENT_PROCESSED: CheckoutStep.ORDER_CREATED,
    }

    def validate_transition(self, target_step: CheckoutStep):
        """Enforce that steps proceed in order; no skipping allowed."""
        expected = self.VALID_TRANSITIONS.get(self.current_step)
        if expected is None:
            raise InvalidStateTransitionError(
                f"No valid transition from {self.current_step.name}. Checkout may be complete."
            )
        if target_step != expected:
            raise InvalidStateTransitionError(
                f"Invalid state transition: cannot go from {self.current_step.name} to "
                f"{target_step.name}. Expected next step: {expected.name}."
            )

    def advance_to(self, target_step: CheckoutStep):
        self.validate_transition(target_step)
        self.current_step = target_step


class CheckoutProcessor:
    """
    Server-side multi-step checkout processor.
    
    All prices, discounts, permissions, and calculations are performed
    using server-side trusted data. Client-supplied values (prices, roles,
    discount eligibility) are NEVER trusted.
    """

    def __init__(self, data_store: ServerDataStore):
        self.store = data_store
        self.sessions: dict[str, CheckoutSession] = {}

    def create_session(self, user_id: str) -> CheckoutSession:
        """Create a new checkout session after verifying the user exists."""
        user = self.store.get_user(user_id)
        if user is None:
            raise AuthorizationError(f"User {user_id} not found.")

        session_id = str(uuid.uuid4())
        session = CheckoutSession(session_id=session_id, user_id=user_id)
        self.sessions[session_id] = session
        return session

    def _get_session(self, session_id: str) -> CheckoutSession:
        session = self.sessions.get(session_id)
        if session is None:
            raise CheckoutError(f"Session {session_id} not found.")
        return session

    def _get_user_for_session(self, session: CheckoutSession) -> User:
        user = self.store.get_user(session.user_id)
        if user is None:
            raise AuthorizationError(f"User {session.user_id} no longer exists.")
        return user

    # =========================================================================
    # STEP 1: Validate Cart Items
    # =========================================================================
    def step1_validate_cart(
        self, session_id: str, client_cart_items: list[dict]
    ) -> CheckoutSession:
        """
        Validate cart items against server-side product catalog.
        
        SECURITY: We ignore any client-supplied prices. We look up the canonical
        price from the server-side product database.
        """
        session = self._get_session(session_id)
        session.validate_transition(CheckoutStep.CART_VALIDATED)

        if not client_cart_items:
            raise ValidationError("Cart is empty.")

        validated_items = []
        subtotal = Decimal("0")
        reserved = []

        seen_product_ids = set()

        for item_data in client_cart_items:
            product_id = item_data.get("product_id")
            quantity = item_data.get("quantity")

            # Basic input validation
            if not product_id or not isinstance(product_id, str):
                raise ValidationError("Each cart item must have a valid product_id.")
            if not isinstance(quantity, int) or quantity <= 0:
                raise ValidationError(
                    f"Invalid quantity for product {product_id}. Must be a positive integer."
                )
            if quantity > 100:
                raise ValidationError(
                    f"Quantity for product {product_id} exceeds maximum of 100."
                )
            if product_id in seen_product_ids:
                raise ValidationError(
                    f"Duplicate product {product_id} in cart. Combine quantities instead."
                )
            seen_product_ids.add(product_id)

            # Server-side product lookup — NEVER trust client-supplied price
            product = self.store.get_product(product_id)
            if product is None:
                raise ValidationError(f"Product {product_id} does not exist.")
            if not product.active:
                raise ValidationError(f"Product {product_id} ({product.name}) is not available.")
            if product.stock < quantity:
                raise ValidationError(
                    f"Insufficient stock for {product.name}. "
                    f"Requested: {quantity}, Available: {product.stock}."
                )

            # Warn if client sent a price (we ignore it)
            if "price" in item_data or "unit_price" in item_data:
                pass  # Silently ignore client-supplied price

            # Server-side price calculation
            unit_price = product.price
            line_total = (unit_price * quantity).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

            # Reserve stock
            if not self.store.reserve_stock(product_id, quantity):
                # Rollback previously reserved stock
                for rid, rqty in reserved:
                    self.store.release_stock(rid, rqty)
                raise ValidationError(
                    f"Failed to reserve stock for {product.name}. Please try again."
                )
            reserved.append((product_id, quantity))

            validated_items.append(ValidatedCartItem(
                product_id=product_id,
                name=product.name,
                quantity=quantity,
                unit_price=unit_price,
                line_total=line_total,
            ))
            subtotal += line_total

        session.validated_items = validated_items
        session.subtotal = subtotal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        session.reserved_stock = reserved
        session.advance_to(CheckoutStep.CART_VALIDATED)

        return session

    # =========================================================================
    # STEP 2: Apply Discount Codes
    # =========================================================================
    def step2_apply_discount(
        self, session_id: str, discount_code: Optional[str] = None
    ) -> CheckoutSession:
        """
        Apply a discount code with full server-side authorization checks.
        
        SECURITY:
        - Discount code validity is checked server-side.
        - User tier/admin status is verified from the server-side user record.
        - Discount value is computed from the server-side discount definition.
        - Client cannot supply their own discount amount or override eligibility.
        """
        session = self._get_session(session_id)
        session.validate_transition(CheckoutStep.DISCOUNTS_APPLIED)

        user = self._get_user_for_session(session)
        discount_amount = Decimal("0")

        if discount_code:
            code_upper = discount_code.strip().upper()

            # Server-side discount code lookup
            dc = self.store.get_discount_code(code_upper)
            if dc is None:
                raise ValidationError(f"Discount code '{discount_code}' does not exist.")
            if not dc.active:
                raise ValidationError(f"Discount code '{discount_code}' is no longer active.")
            if dc.max_uses != -1 and dc.current_uses >= dc.max_uses:
                raise ValidationError(f"Discount code '{discount_code}' has reached its usage limit.")

            # Server-side authorization: admin-only codes
            if dc.admin_only:
                # Check server-side user record, NOT client-supplied role
                if not user.is_admin:
                    raise AuthorizationError(
                        f"Discount code '{discount_code}' is restricted. "
                        f"You do not have permission to use this code."
                    )

            # Server-side authorization: tier-restricted codes
            if dc.required_tier is not None:
                if not user_meets_tier_requirement(user, dc.required_tier):
                    raise AuthorizationError(
                        f"Discount code '{discount_code}' requires {dc.required_tier.value} "
                        f"tier or higher. Your tier: {user.tier.value}."
                    )

            # Minimum order amount check (against server-computed subtotal)
            if session.subtotal < dc.min_order_amount:
                raise ValidationError(
                    f"Discount code '{discount_code}' requires a minimum order of "
                    f"${dc.min_order_amount}. Your subtotal: ${session.subtotal}."
                )

            # Product-specific discount check
            if dc.allowed_product_ids is not None:
                applicable_total = Decimal("0")
                for vi in session.validated_items:
                    if vi.product_id in dc.allowed_product_ids:
                        applicable_total += vi.line_total
                if applicable_total == Decimal("0"):
                    raise ValidationError(
                        f"Discount code '{discount_code}' is not applicable to any items in your cart."
                    )
                base_for_discount = applicable_total
            else:
                base_for_discount = session.subtotal

            # Server-side discount calculation
            if dc.discount_type == "percentage":
                discount_amount = (base_for_discount * dc.value / Decimal("100")).quantize(
                    Decimal("0.01"), rounding=ROUND_HALF_UP
                )
            elif dc.discount_type == "fixed":
                discount_amount = min(dc.value, base_for_discount)
            else:
                raise CheckoutError(f"Unknown discount type: {dc.discount_type}")

            # Discount cannot exceed subtotal
            discount_amount = min(discount_amount, session.subtotal)

            session.discount_code = code_upper
            self.store.increment_discount_usage(code_upper)
        else:
            session.discount_code = None

        session.discount_amount = discount_amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        session.taxable_amount = (session.subtotal - session.discount_amount).quantize(
            Decimal("0.01"), rounding=ROUND_HALF_UP
        )
        session.advance_to(CheckoutStep.DISCOUNTS_APPLIED)

        return session

    # =========================================================================
    # STEP 3: Calculate Tax
    # =========================================================================
    def step3_calculate_tax(
        self, session_id: str, shipping_state: str
    ) -> CheckoutSession:
        """
        Calculate tax based on server-side tax rates.
        
        SECURITY: Tax rate is looked up from server-side config, not client-supplied.
        """
        session = self._get_session(session_id)
        session.validate_transition(CheckoutStep.TAX_CALCULATED)

        if not shipping_state or not isinstance(shipping_state, str):
            raise ValidationError("A valid shipping state is required for tax calculation.")

        state_clean = shipping_state.strip().upper()
        if len(state_clean) != 2:
            raise ValidationError("Shipping state must be a 2-letter state code.")

        # Server-side tax rate lookup
        tax_config = self.store.get_tax_config(state_clean)
        tax_amount = (session.taxable_amount * tax_config.rate).quantize(
            Decimal("0.01"), rounding=ROUND_HALF_UP
        )

        session.tax_state = state_clean
        session.tax_amount = tax_amount
        session.total = (session.taxable_amount + tax_amount).quantize(
            Decimal("0.01"), rounding=ROUND_HALF_UP
        )
        session.advance_to(CheckoutStep.TAX_CALCULATED)

        return session

    # =========================================================================
    # STEP 4: Process Payment
    # =========================================================================
    def step4_process_payment(
        self, session_id: str, payment_method: dict
    ) -> CheckoutSession:
        """
        Process payment using the server-computed total.
        
        SECURITY:
        - The charge amount is the server-computed total, NOT client-supplied.
        - Payment token/method is validated server-side.
        - Idempotency is enforced via session state.
        """
        session = self._get_session(session_id)
        session.validate_transition(CheckoutStep.PAYMENT_PROCESSED)

        if session.total <= Decimal("0"):
            raise PaymentError("Invalid total amount for payment.")

        # Validate payment method structure
        method_type = payment_method.get("type")
        if method_type not in ("credit_card", "debit_card", "paypal", "test"):
            raise ValidationError(f"Unsupported payment method: {method_type}")

        if method_type in ("credit_card", "debit_card"):
            token = payment_method.get("token")
            if not token or not isinstance(token, str):
                raise ValidationError("Payment token is required for card payments.")

        # SECURITY: Charge the SERVER-COMPUTED total, never a client-supplied amount
        if "amount" in payment_method:
            client_amount = Decimal(str(payment_method["amount"]))
            if client_amount != session.total:
                raise PaymentError(
                    f"Payment amount mismatch. Client sent ${client_amount}, "
                    f"server expects ${session.total}. Possible tampering detected."
                )

        # Simulate payment processing
        payment_id = f"PAY-{uuid.uuid4().hex[:12].upper()}"
        payment_success = self._simulate_payment_gateway(
            payment_id=payment_id,
            amount=session.total,
            method=payment_method,
        )

        if not payment_success:
            # Release reserved stock on payment failure
            self._rollback_stock(session)
            raise PaymentError("Payment processing failed. Please try again.")

        # Record payment in server ledger
        self.store.record_payment(payment_id, {
            "payment_id": payment_id,
            "session_id": session.session_id,
            "user_id": session.user_id,
            "amount": str(session.total),
            "method_type": method_type,
            "status": "completed",
            "timestamp": time.time(),
        })

        session.payment_id = payment_id
        session.advance_to(CheckoutStep.PAYMENT_PROCESSED)

        return session

    def _simulate_payment_gateway(
        self, payment_id: str, amount: Decimal, method: dict
    ) -> bool:
        """Simulate a payment gateway call. Returns True on success."""
        # In production, this would call Stripe, PayPal, etc.
        # Simulate failure for specific test scenarios
        if method.get("token") == "FAIL_TOKEN":
            return False
        if method.get("type") == "test" and method.get("should_fail"):
            return False
        return True

    def _rollback_stock(self, session: CheckoutSession):
        """Release all reserved stock for a failed checkout."""
        for product_id, quantity in session.reserved_stock:
            self.store.release_stock(product_id, quantity)
        session.reserved_stock = []

    # =========================================================================
    # STEP 5: Create Order Record
    # =========================================================================
    def step5_create_order(self, session_id: str) -> Order:
        """
        Create the final order record.
        
        SECURITY: All order data comes from the server-side session state,
        which was computed from trusted data in previous steps.
        """
        session = self._get_session(session_id)
        session.validate_transition(CheckoutStep.ORDER_CREATED)

        order_id = f"ORD-{uuid.uuid4().hex[:12].upper()}"

        order = Order(
            order_id=order_id,
            user_id=session.user_id,
            items=[
                {
                    "product_id": vi.product_id,
                    "name": vi.name,
                    "quantity": vi.quantity,
                    "unit_price": str(vi.unit_price),
                    "line_total": str(vi.line_total),
                }
                for vi in session.validated_items
            ],
            subtotal=session.subtotal,
            discount_amount=session.discount_amount,
            tax_amount=session.tax_amount,
            total=session.total,
            discount_code_used=session.discount_code,
            status=OrderStatus.COMPLETED,
            created_at=time.time(),
        )

        self.store.save_order(order)
        session.order_id = order_id
        session.advance_to(CheckoutStep.ORDER_CREATED)

        return order

    # =========================================================================
    # Convenience: Full checkout pipeline
    # =========================================================================
    def full_checkout(
        self,
        user_id: str,
        cart_items: list[dict],
        discount_code: Optional[str],
        shipping_state: str,
        payment_method: dict,
    ) -> Order:
        """
        Execute the complete checkout pipeline.
        Each step depends on and validates the previous step's output.
        """
        session = self.create_session(user_id)
        sid = session.session_id

        try:
            self.step1_validate_cart(sid, cart_items)
            self.step2_apply_discount(sid, discount_code)
            self.step3_calculate_tax(sid, shipping_state)
            self.step4_process_payment(sid, payment_method)
            order = self.step5_create_order(sid)
            return order
        except Exception:
            # On any failure, attempt to rollback reserved stock
            session = self._get_session(sid)
            if session.current_step.value < CheckoutStep.PAYMENT_PROCESSED.value:
                self._rollback_stock(session)
            raise


