    store = ServerDataStore()
    processor = CheckoutProcessor(store)

    order = processor.full_checkout(
        user_id="USER002",  # Bob, Gold tier
        cart_items=[
            {"product_id": "PROD002", "quantity": 1},
            {"product_id": "PROD004", "quantity": 1},
        ],
        discount_code="GOLD25",
        shipping_state="TX",
        payment_method={"type": "credit_card", "token": "tok_visa_4242"},
    )

    print(f"Order ID: {order.order_id}")
    print(f"User: Bob (Gold tier)")
    print(f"Subtotal: ${order.subtotal}")
    print(f"Discount ({order.discount_code_used}): -${order.discount_amount}")
    print(f"Tax: ${order.tax_amount}")
    print(f"Total: ${order.total}")


