def demo_security_violations():
    print_separator("DEMO 5: Security violation tests")

    store = ServerDataStore()
    processor = CheckoutProcessor(store)

    # Test 1: Basic user trying admin-only discount
    print("\n--- Test: Basic user trying admin-only discount ---")
    try:
        processor.full_checkout(
            user_id="USER001",  # Alice, Basic tier
            cart_items=[{"product_id": "PROD002", "quantity": 1}],
            discount_code="ADMIN50",
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "tok_visa_4242"},
        )
    except AuthorizationError as e:
        print(f"BLOCKED: {e}")

    # Test 2: Basic user trying gold-tier discount
    print("\n--- Test: Basic user trying gold-tier discount ---")
    try:
        processor.full_checkout(
            user_id="USER001",
            cart_items=[
                {"product_id": "PROD002", "quantity": 1},
                {"product_id": "PROD003", "quantity": 1},
            ],
            discount_code="GOLD25",
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "tok_visa_4242"},
        )
    except AuthorizationError as e:
        print(f"BLOCKED: {e}")

    # Test 3: Client-supplied price is ignored
    print("\n--- Test: Client-supplied price ignored (server uses canonical price) ---")
    order = processor.full_checkout(
        user_id="USER001",
        cart_items=[
            {"product_id": "PROD001", "quantity": 1, "price": "0.01"},  # Attempted price override
        ],
        discount_code=None,
        shipping_state="CA",
        payment_method={"type": "credit_card", "token": "tok_visa_4242"},
    )
    print(f"Client sent price: $0.01, Server charged: ${order.total} (based on canonical price $29.99)")

    # Test 4: Out-of-stock product
    print("\n--- Test: Out-of-stock product ---")
    try:
        processor.full_checkout(
            user_id="USER001",
            cart_items=[{"product_id": "PROD005", "quantity": 1}],  # 0 stock
            discount_code=None,
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "tok_visa_4242"},
        )
    except ValidationError as e:
        print(f"BLOCKED: {e}")

    # Test 5: Expired discount code
    print("\n--- Test: Expired discount code ---")
    try:
        processor.full_checkout(
            user_id="USER001",
            cart_items=[{"product_id": "PROD002", "quantity": 1}],
            discount_code="EXPIRED10",
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "tok_visa_4242"},
        )
    except ValidationError as e:
        print(f"BLOCKED: {e}")

    # Test 6: Maxed-out discount code
    print("\n--- Test: Maxed-out discount code ---")
    try:
        processor.full_checkout(
            user_id="USER001",
            cart_items=[{"product_id": "PROD002", "quantity": 1}],
            discount_code="MAXED_OUT",
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "tok_visa_4242"},
        )
    except ValidationError as e:
        print(f"BLOCKED: {e}")

    # Test 7: Nonexistent product
    print("\n--- Test: Nonexistent product ---")
    try:
        processor.full_checkout(
            user_id="USER001",
            cart_items=[{"product_id": "FAKE_PRODUCT", "quantity": 1}],
            discount_code=None,
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "tok_visa_4242"},
        )
    except ValidationError as e:
        print(f"BLOCKED: {e}")


def demo_step_skipping():
    print_separator("DEMO 6: Step-skipping prevention")

    store = ServerDataStore()
    processor = CheckoutProcessor(store)

    session = processor.create_session("USER001")
    sid = session.session_id

    # Try to skip directly to tax calculation
    print("\n--- Test: Skip to tax calculation without validating cart ---")
    try:
        processor.step3_calculate_tax(sid, "CA")
    except InvalidStateTransitionError as e:
        print(f"BLOCKED: {e}")

    # Try to skip to payment
    print("\n--- Test: Skip to payment without prior steps ---")
    try:
        processor.step4_process_payment(sid, {"type": "credit_card", "token": "tok_visa_4242"})
    except InvalidStateTransitionError as e:
        print(f"BLOCKED: {e}")

    # Try to skip to order creation
    print("\n--- Test: Skip to order creation without prior steps ---")
    try:
        processor.step5_create_order(sid)
    except InvalidStateTransitionError as e:
        print(f"BLOCKED: {e}")

    # Now do step 1 properly, then try to skip to step 4
    processor.step1_validate_cart(sid, [{"product_id": "PROD001", "quantity": 1}])
    print("\n--- Test: After step 1, skip to payment (step 4) ---")
    try:
        processor.step4_process_payment(sid, {"type": "credit_card", "token": "tok_visa_4242"})
    except InvalidStateTransitionError as e:
        print(f"BLOCKED: {e}")


def demo_payment_failure():
    print_separator("DEMO 7: Payment failure with stock rollback")

    store = ServerDataStore()
    processor = CheckoutProcessor(store)

    initial_stock = store.get_product("PROD001").stock
    print(f"Initial stock for PROD001: {initial_stock}")

    try:
        processor.full_checkout(
            user_id="USER001",
            cart_items=[{"product_id": "PROD001", "quantity": 3}],
            discount_code=None,
            shipping_state="CA",
            payment_method={"type": "credit_card", "token": "FAIL_TOKEN"},
        )
    except PaymentError as e:
        print(f"Payment failed: {e}")

    restored_stock = store.get_product("PROD001").stock
    print(f"Stock after failed payment: {restored_stock}")
    print(f"Stock properly restored: {restored_stock == initial_stock}")


def demo_payment_amount_tampering():
    print_separator("DEMO 8: Payment amount tampering detection")

    store = ServerDataStore()
    processor = CheckoutProcessor(store)

    session = processor.create_session("USER001")
    sid = session.session_id

    processor.step1_validate_cart(sid, [{"product_id": "PROD002", "quantity": 1}])
    processor.step2_apply_discount(sid, None)
    processor.step3_calculate_tax(sid, "CA")

    print(f"Server-computed total: ${session.total}")

    # Try to pay a different (lower) amount
    print("\n--- Test: Client sends tampered payment amount ---")
    try:
        processor.step4_process_payment(sid, {
            "type": "credit_card",
            "token": "tok_visa_4242",
            "amount": "1.00",  # Tampered amount
        })
    except PaymentError as e:
        print(f"BLOCKED: {e}")


